Use dbStockG27GoCreate Table tbStaff (	StaffID smallint Primary Key, 	StaffNameKH nvarchar (30) Collate SQL_Latin1_General_CP850_Bin, 	StaffNameEN varchar (30), 	Sex varchar (6), 	BirthDate date, 	Phone varchar (20), 	ContactAddress varchar(255), 	StaffPosition varchar (150), 	Salary money, 	HiredDate date, 	IsStopWork bit)GoCreate Table tbSupplier (	SupplierID tinyint Primary Key Identity (1,1), 	SupplierName varchar (200), 	SupplierPhone varchar (30), 	SupplierAddress varchar (200))GoCreate Table tbProduct (	ProductID smallint Primary Key Identity(1,1), 	ProductName varchar (150), StockQty smallint, 	UnitPrice money, SaleUnitPrice money, 	Category varchar(150))GoCreate Table tbImport (	ImportID bigint Primary Key Identity(1, 1), 	ImportDate date, SupplierID Tinyint, StaffID smallint, 	StaffNameKH nvarchar (30) Collate SQL_Latin1_General_CP850_Bin, 	StaffNameEN varchar (30), StaffPosition varchar (150), 	TotalAmount money, 	Foreign Key (SupplierID) References tbSupplier (SupplierID) 		On Delete Cascade on Update Cascade, 	Foreign Key (StaffID) References tbStaff (StaffID) 		On Delete Cascade on Update Cascade)GoCreate Table tbImportDetail (	ImportID Bigint, 	ProductID smallint, 	ImportQty smallint, 	UnitPrice money, 	Amount money, 	Foreign Key(ImportID) References tbImport(ImportID) 		On Delete Cascade On Update Cascade, 	Foreign Key(ProductID) References tbProduct(ProductID) 		On Delete Cascade On Update Cascade, 	Primary Key(ImportID, ProductID))GoINSERT INTO tbStaff VALUES 	(1, N'ចាន់ តុលា', 'Chan Tola', 'Male', '12/25/1990', '(012) 838-838', 	 'Phnom Penh', 'Manager', 2000, '1/1/2020', 0),	(2, N'គឹម ធីតា', 'Kim Thida', 'Female', '10/15/1999', '(085) 454-454', 	 'Phnom Penh', 'Secretary', 350, '1/1/2020', 0),	(3, N'ឡុង ម៉ាលី', 'Long Maly', 'Female', '02/13/1999', '(085) 654-323', 	 'Phnom Penh', 'Cashier', 200, '1/1/2020', 0),	(4, N'ឡុង លីណា', 'Long Lyna', 'Female', '06/18/2000', '(085) 874-963', 	 'Phnom Penh', 'Cashier', 200, '1/1/2020', 0),	(5, N'លឹម វុទ្ធី', 'Lim Vuthy', 'Male', '09/23/1991', '(085) 124-763', 	 'Kandal', 'Security', 130, '1/1/2020', 0), 	(6, N'យឹម ស៊ីណា', 'Yim Sina', 'Male', '07/22/1992', '(085) 384-356', 	 'Phnom Penh', 'Security', 130, '1/1/2020', 0)Go-- Create User-Defined Table TypesGoCREATE TYPE structImportMaster As Table (	ImportDate Date, SupplierID Tinyint, 	SupplierName varchar(100), SupplierPhone varchar(15), 	SupplierAddress varchar(255), StaffID Smallint, 	StaffNameKH nvarchar(35), StaffNameEN varchar(25), 	StaffPosition varchar(150), TotalAmount Money)GoCREATE TYPE structImportDetail As Table (	ProductID Smallint, 	ProductName Varchar(100),	Category Varchar(100), 	ImportQty Smallint, 	UnitPrice Money, 		Amount Money)GoCreate Procedure spRunSQL(@sql nText) AsBegin	Exec(@sql)EndGoUSE dbStockG27GOCreate PROCEDURE spImportInserted (	@suImport As structImportMaster Readonly,	@suImportDetail As structImportDetail Readonly)ASBegin	Begin Try		Declare @spid Tinyint, @impid int		Declare @impDate Date, @sid Smallint, @snKH nvarchar(35)		Declare @snEN varchar(30), @pos varchar(150), @ta Money 			Begin Transaction;			Select @spid = SupplierID From @suImport;		If(@spid = 0) --New Supplier		 Begin			Insert Into tbSupplier(SupplierName, SupplierPhone,			SupplierAddress) Select SupplierName, SupplierPhone, 				SupplierAddress From @suImport;			Select @spid = MAX(SupplierID) From tbSupplier;					Select @impDate = ImportDate, @sid = StaffID,				@snKH = StaffNameKH, @snEN = StaffNameEN, 				@pos = StaffPosition, @ta = TotalAmount 			From @suImport;			Insert Into tbImport(ImportDate, SupplierID, StaffID, StaffNameKH, 						StaffNameEN, StaffPosition, TotalAmount) 			Values(@impDate, @spid, @sid, @snKH, @snEN, @pos, @ta);		  End		Else --Old Supplier		 Begin			Insert Into tbImport(ImportDate, SupplierID, StaffID, StaffNameKH, 				StaffNameEN, StaffPosition, TotalAmount) Select ImportDate, 				SupplierID, StaffID, StaffNameKH, StaffNameEN, 				StaffPosition, TotalAmount From @suImport;		 End 		Select @impid = MAX(ImportID) From tbImport;		Declare @pid Smallint, @pn varchar(100), @qty Smallint, @up Money		Declare @cg varchar(150), @a Money		Declare csDetail Cursor FORWARD_ONLY		For Select * From @suImportDetail		Open csDetail		Fetch Next From csDetail Into @pid, @pn, @cg, @qty, @up, @a		While(@@FETCH_STATUS = 0)		 Begin			If(@pid = 0) --New Product			 Begin				Insert Into tbProduct(ProductName, StockQty, UnitPrice, 				SaleUnitPrice, Category) Values (@pn, @qty, @up, @up + 100, @cg);				Select @pid = MAX(ProductID) From tbProduct			 End			Else	--Old Product					 Begin				Update tbProduct Set UnitPrice = (StockQty*UnitPrice + 					@qty*@up)/(StockQty + @qty), StockQty = StockQty + @qty 				Where ProductID = @pid; 				Update tbProduct Set SaleUnitPrice = UnitPrice + 100 				Where ProductID = @pid; 		 			 End			Insert Into tbImportDetail(ImportID, ProductID, ImportQty, 								UnitPrice, Amount) Values(@impid, @pid, @qty, @up, @a);			Fetch Next From csDetail Into @pid, @pn, @cg, @qty, @up, @a		 End		Close csDetail		Deallocate csDetail 		Commit Transaction;	End Try	Begin Catch		Rollback Transaction;    	Print 'Transaction failed. Error: ' + ERROR_MESSAGE();	End CatchEnd